const commands = [
  "help", "gpr", "gapr", "lp"
]

const months = [
  "jan", "feb", "mar", "apr", "may", "jun", "jul", "aug",
  "sep", "oct", "nov", "dec"
]

let chatId = $input.first().json.message.chat.id
let message = $input.first().json.message.text
let words = message.split(" ")

if (words.length == 0) {
  return {
    "command": "error",
    "message": "unknown command",
    "chat_id": chatId
  }
}

let commandIdx = commands.findIndex((c) => {
    return c == words[0].toLowerCase()
})
if (commandIdx == -1) {
  return {
    "command": "error",
    "message": "unknown command",
    "chat_id": chatId
  }
}

let command = words[0]

// git pull request
if (command == 'gpr') {
  let repoName = words[1]
  let sourceBranch = words[2]
  let targetBranch = words[3]

  if (repoName == '') {
    return {
      "command": "error",
      "message": "repo name is empty",
      "chat_id": chatId
    }
  }
  if (sourceBranch == '') {
    return {
      "command": "error",
      "message": "source branch is empty",
      "chat_id": chatId
    }
  }
  if (targetBranch == '') {
    return {
      "command": "error",
      "message": "target branch is empty",
      "chat_id": chatId
    }
  }

  return {
    "command": command,
    "repo_name": repoName,
    "source_branch": sourceBranch,
    "target_branch": targetBranch
  }
}

// gap: git approve
if (command == "gapr") {
  let links = words.slice(1, words.length)

  return {
    "command": command,
    "chat_id": chatId,
    "pull_requests": links
  }
}

// lp: cost reporting
if (command == "lp") {
  const category = words[1]
  if (category == 'categories') {
    return {
      "chat_id": chatId,
      "command": "lp_categories"
    }
  }

  if (category == 'report') {
    let month = words[2]
    let year = parseInt(words[3])
    const costCategory = words[4]

    const now = new Date()
    if (isNaN(year) || year > now.getFullYear()) {
      year = now.getFullYear()
    }

    const idxMonth = months.findIndex((val) => {
      return val == month
    })
    if (idxMonth == -1) {
      month = months[now.getMonth()]
    }

    return {
      "chat_id": chatId,
      "command": "lp_report",
      "year": year,
      "month": month,
      "cost_category": costCategory
    }
  }

  const cost = parseFloat(words[2])
  if (isNaN(cost)) {
    return {
      "command": "error",
      "message": "Invalid Parameter for command 'lp' cost",
      "chat_id": chatId
    }
  }

  return {
    "chat_id": chatId,
    "command": command,
    "category": words[1],
    "cost": words[2],
    "description": words.slice(3, words.length).join(" ")
  }
}

return {
  "command": command,
  "message": words.slice(1, words.length).join(" "),
  "chat_id": chatId
}

let links = $input.first().json.pull_requests

let data = []
links.forEach((val) => {
  let words = val.split("/")
  let items = words.slice(words.length-4, words.length)

  if (items.length == 0 || items[2] != "pull") {
    data.push({
      "url": val,
      "err_message": "wrong url"
    })
  }

  // example: https://github.com/waresix/navi-core-service/pull/3865
  let ownerName = items[0]
  let repoName = items[1]
  let pullRequestId = items[3]

  data.push({
    "url": val,
    "chat_id": $input.first().json.chat_id,
    "repo_name": repoName,
    "owner_name": ownerName,
    "pull_request_number": pullRequestId,
    "err_message": null
  })
})

return data

let reviews = $input.all()

const idx = parseInt($runIndex.toString())
const pr_data = $('Proccess Data').all()[idx]
const data = pr_data.json

const result = {
  chat_id: data.chat_id,
  valid: true,
  owner_name: data.owner_name,
  repo_name: data.repo_name,
  pr_number: data.pull_request_number
}

if (reviews.length == 1 && Object.keys(reviews[0].json).length == 0) {
  return result
}

for (const rev of reviews) {
  const item = rev.json

  if (item.user.login == 'kcchandra-w6' && item.state == 'APPROVED') {
    result.valid = false
    return result
  }
}

return result;

let pullRequests = $input.all()
let sourceBranch = $('Access Command').first().json.source_branch
let targetBranch = $('Access Command').first().json.target_branch

for (let i=0; i<pullRequests.length; i++) {
  let pr = pullRequests[i].json

  let headBranch = pr.head.ref
  let baseBranch = pr.base.ref

  if (headBranch == sourceBranch && baseBranch == targetBranch) {
    return {
      "pr_exists": true,
      "pr_url": pr.html_url,
      "repo_owner_name": null,
      "repo_name": null,
      "pr_title": pr.title,
      "body": pr.body
    }
  }
}

return {
  "pr_exists": false,
  "pr_url": null,
  "repo_owner_name": $('Get Repository Branch').first().json.owner.login,
  "repo_name": $('Get Repository Branch').first().json.name,
  "pr_title": $('Switch').first().json.source_branch,
  "body": "Created by n8n",
  "head": sourceBranch,
  "base": targetBranch
}

const input = $('Access Command').first().json

let categoryIsExist = false
for (const item of $input.all()) {
  if (input.category == item.json.category) {
    categoryIsExist = true
    break
  }
}

if (!categoryIsExist) {
  return {
    "is_valid": false,
    "error_message": "😡 category is unrecognized",
    "chat_id": input.chat_id
  }
}

const bulan = [
  "januari", "februari", "maret", "april", "mei", 
  "juni", "juli", "agustus", "september", "oktober", 
  "november", "desember"
]

const now = new Date()
const docName = `cost-${now.getFullYear()}`
const sheetName = bulan[now.getMonth()]

return {
  ...input,
  "request_date": now.toLocaleDateString(),
  "is_valid": true,
  "doc_name": docName,
  "sheet_name": sheetName
}

