const baseInput = $('Separate Command Report').first().json
const createdSpreadsheetID = $('Create Cost Sheet').first().json.spreadsheetId

return {
  ...baseInput,
  "spreadsheet_id": createdSpreadsheetID
}

const baseInput = $('Separate Command Report').first().json
const existsFileID = $('Search files and folders').first().json.id

return {
  ...baseInput,
  "spreadsheet_id": existsFileID,
}

let text = `Available Categories 👇:`

for (const item of $input.all()) {
  text += `
  - ${item.json.category}`
}

return {
  content: text,
  chat_id: $('Access Command').first().json.chat_id
}

const reportSummary = $('Get Report Summary Total').first().json
let totalCost = 0
let costCategory = reportSummary.cost_category || ""

const isCategoryGeneral = costCategory === 'general'

for (const row of $input.all()) {
  const item = row.json

  if (!isCategoryGeneral && 
      item.Category !== costCategory) {
    continue
  }

  totalCost += item.Cost
}

const month = reportSummary?.sheet_name
const year = reportSummary?.year

const formatedCost = new Intl.NumberFormat('id-ID', {
    style: 'currency',
    currency: 'IDR',
    minimumFractionDigits: 2, // Indonesian Rupiah typically uses two decimal places
}).format(totalCost)

if (costCategory === "") {
  costCategory = "general"
}

return {
  chat_id: reportSummary.chat_id,
  date: month + " " + year,
  total_cost: formatedCost,
  cost_category: costCategory
}

